import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

// Định nghĩa cấu trúc dữ liệu nhân vật chung
const RoleSchema = z.object({
  Miêu_tả_cảnh_tượng: z.string().describe('Miêu tả khách quan của màn hình hiện tại').prefault(''),
  Suy_nghĩ_nội_tâm: z.string().describe('Độc thoại nội tâm hiện tại của nhân vật').prefault(''),
  Họ_tên: z.string().prefault('Vô danh'),
  Tuổi: z.string().prefault('Vô danh'),
  Giới_tính: z.string().prefault('Nữ giới'),
  Thân_phận: z.string().prefault(''),
  Tính_cách: z.string().describe('Đặc điểm tính cách cốt lõi của nhân vật').prefault(''),

  Kích_thước_ngực: z.string().describe('Ví dụ: D Cup, bạo nhũ, v.v.').prefault('Vô danh'),
  Trang_phục: z.object({
    Thân_trên: z.string().prefault(''),
    Thân_dưới: z.string().prefault(''),
    Đồ_lót: z.string().prefault(''),
    Giày_tất: z.string().prefault(''),
    Phụ_kiện: z.string().prefault(''),
  }),
  Đặc_tả: z.object({
    Bộ_phận: z.string().prefault(''),
    Miêu_tả: z.string().prefault(''),
  }),

  Chỉ_số_mang_thai: z.coerce.number().describe('0-100, tiến độ thụ thai').transform(v => _.clamp(v, 0, 100)).prefault(0),
  Có_phải_xử_nữ_không: z.boolean().describe('Có giữ gìn tấm thân xử nữ hay không').prefault(true),
  Chỉ_số_hủ_hóa: z.coerce.number().describe('0-49 kháng cự, 50-99 dao động, 100+ chìm đắm').transform(v => _.clamp(v, 0, 200)).prefault(0),
  Chỉ_số_lý_trí: z.coerce.number().describe('100 là tỉnh táo, 0 là băng hoại').transform(v => _.clamp(v, 0, 100)).prefault(100),
  Độ_hưng_phấn: z.coerce.number().describe('Mức độ kích thích sinh lý hiện tại').transform(v => _.clamp(v, 0, 100)).prefault(0),
  Lượng_tinh_dịch: z.coerce.number().describe('Lượng tinh dịch tích lũy trong cơ thể ml').min(0).prefault(0),
  Độ_lệ_thuộc: z.coerce.number().describe('Sự phụ thuộc tình cảm đối với nhân vật chính').transform(v => _.clamp(v, 0, 100)).prefault(0),
  Tiến_độ_thu_thập_ID: z.coerce.number().describe('Tiến độ thu thập ID của nhân vật chính %').transform(v => _.clamp(v, 0, 100)).prefault(0),
  Trạng_thái_kỳ_sinh_lý: z.enum(['Kỳ an toàn', 'Kỳ rụng trứng', 'Kỳ kinh nguyệt']).describe('Trạng thái chu kỳ sinh lý hiện tại').prefault('Kỳ an toàn'),
});

export const Schema = z.object({
  // Biến toàn cục thế giới
  Thế_giới: z.object({
    Ngày: z.string().describe('Ngày hiện tại, ví dụ Ngày 1 tháng 1 năm 2024').prefault('Ngày 1 tháng 1 năm 2024'),
    Thời_gian_hiện_tại: z.string().prefault('Buổi sáng'),
    Địa_điểm_hiện_tại: z.string().prefault('Trường học'),
    Nhân_vật_tương_tác_hiện_tại: z.string().prefault(''),
  }),

  // Trạng thái nhân vật chính
  Nhân_vật_chính: z.object({
    Trạng_thái: z.string().prefault('Bình thường'),
    Thể_lực: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(100),
    Trữ_lượng_tinh_dịch: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(100),
    Làm_nguội_giao_thức_truyền_tống: z.boolean().describe('Có đang trong thời gian làm nguội hay không').prefault(false),
  }),

  // Thùng chứa chung cho tất cả các nhân vật nữ
  Nhân_vật: z.record(z.string().describe('Tên nhân vật'), RoleSchema),

  // Động thái mạng
  Động_thái_mạng: z.object({
    Bài_đăng_hot: z.object({
      Tiêu_đề: z.string().prefault(''),
      Nội_dung_bài_đăng: z.string().prefault(''),
      Bình_luận: z.record(
        z.string().describe('ID người dùng'),
        z.string().describe('Nội dung bình luận')
      ).prefault({}),
    }).prefault({
      Tiêu_đề: '',
      Nội_dung_bài_đăng: '',
      Bình_luận: {},
    }),
  }).prefault({
    Bài_đăng_hot: {
      Tiêu_đề: '',
      Nội_dung_bài_đăng: '',
      Bình_luận: {},
    },
  }),
});

$(() => {
  registerMvuSchema(Schema);
})

