    .post-content {
      padding: 10px;
      font-size: 12px;
      color: var(--text-secondary);
      line-height: 1.7;
      white-space: pre-wrap;
    }
    .post-actions {
      display: flex;
      gap: 16px;
      padding: 8px 10px;
      border-top: 1px solid var(--border-light);
      font-size: 11px;
      color: var(--text-muted);
    }
    .post-act { display: flex; align-items: center; gap: 4px; cursor: pointer; transition: color 0.2s; }
    .post-act:hover { color: var(--accent-main); }
    .cmt-section { margin-top: 10px; }
    .cmt-head {
