    function showExplain(name) {
      const info = explains[name];
      if (!info) return;
      let html = `<div class="modal-head"><div class="modal-title"><i class="fas ${info.icon}"></i><span>${info.title}</span></div><button class="modal-close"><i class="fas fa-times"></i></button></div><div class="modal-body"><p>${info.desc}</p>`;
      if (info.stages) {
        html += '<h4><i class="fas fa-layer-group"></i>Giai đoạn trị số</h4>';
        info.stages.forEach(s => { html += `<div class="stage-box"><div class="stage-title">${s.r} - ${s.n}</div><div>${s.d}</div></div>`; });
      }
      if (info.tips) {
        html += '<h4><i class="fas fa-lightbulb"></i>Quy tắc thay đổi</h4><ul>';
        info.tips.forEach(t => { html += `<li>${t}</li>`; });
        html += '</ul>';
      }
      html += '</div>';
      $('#modal-content').html(html);
      $('#modal').addClass('show');
    }
    function closeModal() { $('.modal').removeClass('show'); }
    function getStage(v) { return v < 50 ? 'Giai đoạn kháng cự' : v < 100 ? 'Giai đoạn dao động' : v < 200 ? 'Giai đoạn chìm đắm' : 'Đọa lạc triệt để'; }
    function getState(v) { return v > 70 ? 'Tỉnh táo' : v > 30 ? 'Hỗn loạn' : 'Băng hoại'; }
    function getSemenDesc(v) {
      if (v <= 50) return '';
      if (v <= 200) return 'Ẩm ướt';
      if (v <= 500) return 'Hơi nhô lên';
      if (v <= 1000) return 'Nhô lên rõ rệt';
      return 'Căng phồng';
    }
    function getUserType(id) {
      const s = id.toLowerCase();
      if (s.includes('贞女') || s.includes('骑士') || s.includes('knight')) return 'knight';
      if (s.includes('鬣狗') || s.includes('hyena') || s.includes('猎手')) return 'hyena';
      return 'normal';
    }
    function getUserBadge(type) {
      if (type === 'knight') return '<span class="cmt-badge knight">Kannyo Kishi</span>';
      if (type === 'hyena') return '<span class="cmt-badge hyena">Hyena-dan</span>';
      return '';
    }
    function setTheme(theme) {
      document.documentElement.setAttribute('data-theme', theme);
      localStorage.setItem('theme', theme);
      $('.theme-btn').removeClass('active');
      $(`.theme-btn[data-theme="${theme}"]`).addClass('active');
    }
    function loadTheme() {
      const saved = localStorage.getItem('theme') || 'white';
      setTheme(saved);
    }
    function populate() {
      const data = getAllVariables();
      const world = _.get(data, 'stat_data.Thế_giới', {});
      const hero = _.get(data, 'stat_data.Nhân_vật_chính', {});
      const roles = _.get(data, 'stat_data.Nhân_vật', {});
      const network = _.get(data, 'stat_data.Động_thái_mạng', {});
      $('#w-date').text(world.Ngày || 'Vô danh');
      $('#w-time').text(world.Thời_gian_hiện_tại || 'Vô danh');
      $('#w-loc').text(world.Địa_điểm_hiện_tại || 'Vô danh');
      $('#w-role').text(world.Nhân_vật_tương_tác_hiện_tại || 'Không');
      $('#h-status').text(hero.Trạng_thái || 'Bình thường');
      $('#h-sta-fill').css('width', `${hero.Thể_lực}%`);
      $('#h-sta-num').text(hero.Thể_lực);
      $('#h-sem-fill').css('width', `${hero.Trữ_lượng_tinh_dịch}%`);
      $('#h-sem-num').text(hero.Trữ_lượng_tinh_dịch);
      $('#h-cd').text(hero.Làm_nguội_giao_thức_truyền_tống ? 'Đang làm nguội' : 'Sẵn sàng').css('color', hero.Làm_nguội_giao_thức_truyền_tống ? 'var(--red)' : 'var(--green)');
      const cnt = Object.keys(roles).length;
      const vir = Object.values(roles).filter(r => r.Có_phải_xử_nữ_không).length;
      const preg = Object.values(roles).filter(r => r.Chỉ_số_mang_thai >= 100).length;
      $('#s-cnt').text(cnt);
      $('#s-vir').text(vir);
      $('#s-preg').text(preg);
      renderRoleBar(roles);
      if (curRole && roles[curRole]) renderRole(roles[curRole]);
      else $('#role-detail').html('<div class="empty"><i class="fas fa-user-slash"></i><p>Vui lòng chọn một nhân vật</p></div>');
      renderNetwork(network);
    }
    function renderRoleBar(roles) {
      const $bar = $('#role-bar');
      $bar.empty();
      const names = Object.keys(roles);
      if (names.length === 0) { $bar.html('<div style="color:var(--text-muted);font-size:11px;">Tạm thời chưa có dữ liệu nhân vật</div>'); return; }
      names.forEach(name => {
        const on = name === curRole;
        $bar.append(`<div class="chip ${on ? 'on' : ''}" data-name="${name}">${name}</div>`);
      });
      if (!curRole && names.length > 0) {
        curRole = names[0];
        $(`.chip[data-name="${curRole}"]`).addClass('on');
      }
    }
    function renderRole(r) {
      const stage = getStage(r.Chỉ_số_hủ_hóa);
      const state = getState(r.Chỉ_số_lý_trí);
      const semenDesc = getSemenDesc(r.Lượng_tinh_dịch);
      const vBadge = r.Có_phải_xử_nữ_không ? '<span class="badge virgin"><i class="fas fa-heart"></i>Xử nữ</span>' : '<span class="badge no-virgin"><i class="fas fa-heart-broken"></i>Đã phá thân</span>';
      let html = `
        <div class="card"><div class="card-head"><i class="fas fa-id-card"></i>Thông tin cơ bản</div><div class="card-body">
          <div class="info-grid">
            <div class="info-box"><div class="num">${r.Tuổi}</div><div class="txt">Tuổi</div></div>
            <div class="info-box"><div class="num">${r.Giới_tính}</div><div class="txt">Giới tính</div></div>
            <div class="info-box"><div class="num">${r.Kích_thước_ngực}</div><div class="txt">Ngực</div></div>
          </div>
          <div class="row"><span class="lbl">Họ tên</span><span class="val hl">${r.Họ_tên}</span></div>
          <div class="row"><span class="lbl">Thân phận</span><span class="val">${r.Thân_phận || 'Vô danh'}</span></div>
          <div class="row"><span class="lbl">Tính cách</span><span class="val">${r.Tính_cách || 'Vô danh'}</span></div>
          <div class="row"><span class="lbl">Trinh tiết</span><span class="val">${vBadge}</span></div>
        </div></div>
        <div class="card"><div class="card-head pink"><i class="fas fa-fire"></i>Hệ thống hủ hóa</div><div class="card-body">
          <div class="row"><span class="lbl" data-stat="Chỉ_số_hủ_hóa">Chỉ số hủ hóa<i class="fas fa-circle-info tip"></i></span><div class="prog-wrap"><div class="prog-track"><div class="prog-fill purple" style="width:${Math.min(r.Chỉ_số_hủ_hóa, 200) / 2}%"></div></div><span class="prog-num purple">${r.Chỉ_số_hủ_hóa}/200</span></div></div>
          <div class="row"><span class="lbl">Giai đoạn hiện tại</span><span class="val"><span class="badge stage">${stage}</span></span></div>
        </div></div>
        <div class="card"><div class="card-head blue"><i class="fas fa-brain"></i>Trạng thái tinh thần</div><div class="card-body">
          <div class="row"><span class="lbl" data-stat="Chỉ_số_lý_trí">Chỉ số lý trí<i class="fas fa-circle-info tip"></i></span><div class="prog-wrap"><div class="prog-track"><div class="prog-fill blue" style="width:${r.Chỉ_số_lý_trí}%"></div></div><span class="prog-num blue">${r.Chỉ_số_lý_trí}/100</span></div></div>
          <div class="row"><span class="lbl">Trạng thái tinh thần</span><span class="val"><span class="badge state">${state}</span></span></div>
        </div></div>
        <div class="card"><div class="card-head orange"><i class="fas fa-heart-pulse"></i>Trạng thái sinh lý</div><div class="card-body">
          <div class="row"><span class="lbl" data-stat="Độ_hưng_phấn">Độ hưng phấn<i class="fas fa-circle-info tip"></i></span><div class="prog-wrap"><div class="prog-track"><div class="prog-fill orange" style="width:${r.Độ_hưng_phấn}%"></div></div><span class="prog-num orange">${r.Độ_hưng_phấn}/100</span></div></div>
          <div class="row"><span class="lbl" data-stat="Chỉ_số_mang_thai">Chỉ số mang thai<i class="fas fa-circle-info tip"></i></span><div class="prog-wrap"><div class="prog-track"><div class="prog-fill pink" style="width:${r.Chỉ_số_mang_thai}%"></div></div><span class="prog-num pink">${r.Chỉ_số_mang_thai}/100</span></div></div>
          <div class="row"><span class="lbl" data-stat="Lượng_tinh_dịch">Lượng tinh dịch<i class="fas fa-circle-info tip"></i></span><span class="val">${r.Lượng_tinh_dịch} ml${semenDesc ? ` <span style="color:var(--pink);font-size:10px;">(${semenDesc})</span>` : ''}</span></div>
          <div class="row"><span class="lbl" data-stat="Trạng_thái_kỳ_sinh_lý">Kỳ sinh lý<i class="fas fa-circle-info tip"></i></span><span class="val"><span class="badge period">${r.Trạng_thái_kỳ_sinh_lý}</span></span></div>
        </div></div>
        <div class="card"><div class="card-head green"><i class="fas fa-heart"></i>Liên kết tình cảm</div><div class="card-body">
          <div class="row"><span class="lbl" data-stat="Độ_lệ_thuộc">Độ lệ thuộc<i class="fas fa-circle-info tip"></i></span><div class="prog-wrap"><div class="prog-track"><div class="prog-fill green" style="width:${r.Độ_lệ_thuộc}%"></div></div><span class="prog-num green">${r.Độ_lệ_thuộc}/100</span></div></div>
          <div class="row"><span class="lbl" data-stat="Tiến_độ_thu_thập_ID">Tiến độ ID<i class="fas fa-circle-info tip"></i></span><div class="prog-wrap"><div class="prog-track"><div class="prog-fill purple" style="width:${r.Tiến_độ_thu_thập_ID}%"></div></div><span class="prog-num purple">${r.Tiến_độ_thu_thập_ID}%</span></div></div>
        </div></div>
        <div class="card"><div class="card-head cyan"><i class="fas fa-tshirt"></i>Trang phục hiện tại</div><div class="card-body">
          <div class="wear-grid">
            <div class="wear-item"><span class="wlbl">Thân trên:</span>${r.Trang_phục.Thân_trên || 'Không'}</div>
            <div class="wear-item"><span class="wlbl">Thân dưới:</span>${r.Trang_phục.Thân_dưới || 'Không'}</div>
            <div class="wear-item"><span class="wlbl">Đồ lót:</span>${r.Trang_phục.Đồ_lót || 'Không'}</div>
            <div class="wear-item"><span class="wlbl">Giày tất:</span>${r.Trang_phục.Giày_tất || 'Không'}</div>
          </div>
          ${r.Trang_phục.Phụ_kiện ? `<div class="wear-item" style="margin-top:6px;"><span class="wlbl">Phụ kiện:</span>${r.Trang_phục.Phụ_kiện}</div>` : ''}
        </div></div>`;
      if (r.Đặc_tả.Bộ_phận && r.Đặc_tả.Miêu_tả) {
        html += `<div class="card"><div class="card-head pink"><i class="fas fa-camera"></i>Ống kính đặc tả</div><div class="card-body"><div class="closeup-box"><div class="closeup-part"><i class="fas fa-crosshairs"></i> ${r.Đặc_tả.Bộ_phận}</div><div class="closeup-desc">${r.Đặc_tả.Miêu_tả}</div></div></div></div>`;
      }
      if (r.Miêu_tả_cảnh_tượng) {
        html += `<div class="card"><div class="card-head"><i class="fas fa-image"></i>Miêu tả cảnh tượng</div><div class="card-body"><div class="scene-box">${r.Miêu_tả_cảnh_tượng}</div></div></div>`;
      }
      if (r.Suy_nghĩ_nội_tâm) {
        html += `<div class="card"><div class="card-head"><i class="fas fa-comment-dots"></i>Suy nghĩ nội tâm</div><div class="card-body"><div class="thought-box">${r.Suy_nghĩ_nội_tâm}</div></div></div>`;
      }
      $('#role-detail').html(html);
    }
    function renderNetwork(network) {
      const $box = $('#net-content');
      const post = network.Bài_đăng_hot || {};
      const title = post.Tiêu_đề || '';
      const content = post.Nội_dung_bài_đăng || '';
      const comments = post.Bình_luận || {};
      if (!title && !content) {
        $box.html('<div class="no-post"><i class="fas fa-rss"></i><p>Tạm thời không có bài đăng hot</p><p style="margin-top:8px;font-size:11px;">Theo sự phát triển của cốt truyện, nơi đây sẽ hiển thị động thái dư luận mạng</p></div>');
        return;
      }
      let html = `<div class="post-card"><div class="post-head"><div class="post-avatar"><i class="fas fa-fire"></i></div><div class="post-meta"><div class="post-author">Chủ đề hot</div><div class="post-time">Đang thảo luận sôi nổi...</div></div><div class="post-tag">Mạng xã hội</div></div>${title ? `<div class="post-title"><i class="fas fa-hashtag" style="color:var(--pink);margin-right:5px;"></i>${title}</div>` : ''}${content ? `<div class="post-content">${content}</div>` : ''}<div class="post-actions"><div class="post-act"><i class="far fa-heart"></i> ${Math.floor(Math.random() * 500) + 100}</div><div class="post-act"><i class="far fa-comment"></i> ${Object.keys(comments).length}</div><div class="post-act"><i class="fas fa-share"></i> Chia sẻ</div></div></div>`;
      const cmts = Object.entries(comments);
      html += `<div class="cmt-section"><div class="cmt-head"><span><i class="fas fa-comments"></i>Khu vực bình luận</span><span style="font-size:10px;color:var(--text-muted);">${cmts.length} dòng</span></div><div class="cmt-list">`;
      if (cmts.length === 0) {
        html += '<div class="no-cmt"><i class="fas fa-comment-slash"></i> Tạm thời chưa có bình luận</div>';
      } else {
        cmts.forEach(([uid, txt]) => {
          const type = getUserType(uid);
          const badge = getUserBadge(type);
          html += `<div class="cmt-item"><div class="cmt-top"><div class="cmt-av"><i class="fas fa-user"></i></div><span class="cmt-user ${type}">${uid}</span>${badge}</div><div class="cmt-text">${txt}</div></div>`;
        });
      }
      html += '</div></div>';
      $box.html(html);
    }
    async function init() {
      await waitGlobalInitialized('Mvu');
      loadTheme();
      populate();
      eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, () => { populate(); });
      $('.tab').on('click', function() {
        const tab = $(this).data('tab');
        $('.tab').removeClass('on');
        $(this).addClass('on');
        $('.pane').removeClass('on');
        $(`#pane-${tab}`).addClass('on');
      });
      $(document).on('click', '.chip', function() {
        curRole = $(this).data('name');
        $('.chip').removeClass('on');
        $(this).addClass('on');
        const data = getAllVariables();
        const roles = _.get(data, 'stat_data.Nhân_vật', {});
        if (roles[curRole]) renderRole(roles[curRole]);
      });
      $(document).on('click', '.lbl[data-stat]', function() {
        showExplain($(this).data('stat'));
      });
      $(document).on('click', '.theme-btn', function() {
        const theme = $(this).data('theme');
        setTheme(theme);
      });
      $(document).on('click', '.modal-close', closeModal);
      $(document).on('click', '.modal', function(e) {
        if ($(e.target).hasClass('modal')) closeModal();
      });
    }
    $(errorCatched(init));
  </script>
</head>
<body>
  <div class="app">
    <div class="header">
      <div class="header-title">Hệ thống quản lý nhân vật</div>
      <div class="header-stats">
        <div class="h-stat"><i class="fas fa-users"></i><span id="s-cnt">0</span>nhân vật</div>
        <div class="h-stat"><i class="fas fa-heart"></i><span id="s-vir">0</span>xử nữ</div>
        <div class="h-stat"><i class="fas fa-baby"></i><span id="s-preg">0</span>mang thai</div>
      </div>
    </div>
    <div class="theme-switcher">
      <span class="theme-label"><i class="fas fa-palette"></i> Chủ đề:</span>
      <div class="theme-btn active" data-theme="white" title="Chủ đề trắng"></div>
      <div class="theme-btn" data-theme="light" title="Chủ đề nhạt"></div>
      <div class="theme-btn" data-theme="dark" title="Chủ đề đen"></div>
      <div class="theme-btn" data-theme="deepdark" title="Chủ đề tối"></div>
    </div>
    <div class="world-bar">
      <div class="w-item"><i class="fas fa-calendar-alt"></i><span id="w-date">Vô danh</span></div>
      <div class="w-item"><i class="fas fa-clock"></i><span id="w-time">Vô danh</span></div>
      <div class="w-item"><i class="fas fa-map-marker-alt"></i><span id="w-loc">Vô danh</span></div>
      <div class="w-item"><i class="fas fa-user-friends"></i><span id="w-role">Không</span></div>
    </div>
    <div class="tabs">
      <button class="tab on" data-tab="roles"><i class="fas fa-users"></i><span>Nhân vật</span></button>
      <button class="tab" data-tab="hero"><i class="fas fa-user"></i><span>Chủ giác</span></button>
      <button class="tab" data-tab="network"><i class="fas fa-rss"></i><span>Mạng</span></button>
    </div>
    <div class="pane on" id="pane-roles">
      <div class="role-bar" id="role-bar"></div>
      <div id="role-detail"></div>
    </div>
    <div class="pane" id="pane-hero">
      <div class="card"><div class="card-head"><i class="fas fa-user-circle"></i>Trạng thái nhân vật chính</div><div class="card-body">
        <div class="row"><span class="lbl">Trạng thái hiện tại</span><span class="val hl" id="h-status">Bình thường</span></div>
        <div class="row"><span class="lbl" data-stat="Thể_lực">Thể lực<i class="fas fa-circle-info tip"></i></span><div class="prog-wrap"><div class="prog-track"><div class="prog-fill cyan" id="h-sta-fill" style="width:100%"></div></div><span class="prog-num cyan" id="h-sta-num">100</span></div></div>
        <div class="row"><span class="lbl" data-stat="Trữ_lượng_tinh_dịch">Trữ lượng tinh dịch<i class="fas fa-circle-info tip"></i></span><div class="prog-wrap"><div class="prog-track"><div class="prog-fill cyan" id="h-sem-fill" style="width:100%"></div></div><span class="prog-num cyan" id="h-sem-num">100</span></div></div>
        <div class="row"><span class="lbl" data-stat="Làm_nguội_giao_thức_truyền_tống">Giao thức truyền tống<i class="fas fa-circle-info tip"></i></span><span class="val" id="h-cd">Sẵn sàng</span></div>
      </div></div>
    </div>
    <div class="pane" id="pane-network">
      <div id="net-content"></div>
    </div>
  </div>
  <div class="modal" id="modal"><div class="modal-box" id="modal-content"></div></div>
</body>
</html>
