entries.content:
---
Quy_tắc_cập_nhật_biến:
  Thế_giới.${Ngày|Thời_gian_hiện_tại|Địa_điểm_hiện_tại|Nhân_vật_tương_tác_hiện_tại}:
    check:
      - Cập nhật khi chuyển cảnh hoặc thời gian tiến triển, duy trì tính liên kết logic

  Nhân_vật_chính:
    ${Thể_lực|Trữ_lượng_tinh_dịch}:
      type: number
      range: 0~100
      check:
        - Thể_lực: Hoạt động kịch liệt -5~-20, nghỉ ngơi +5~+10, ăn uống +10~+20, ngủ hồi phục 80~100. Dưới 20 không thể hoạt động kịch liệt, dưới 10 sẽ ngất xỉu
        - Trữ_lượng_tinh_dịch: Xuất tinh -10~-50, mỗi giờ +2~+5, ngủ +40~+60. Ảnh hưởng miêu tả: 70-100 đậm đặc/30-69 bình thường/10-29 loãng/0-9 bắn khan

    Làm_nguội_giao_thức_truyền_tống:
      type: boolean
      check:
        - Sau khi sử dụng truyền tống khẩn cấp sẽ biến thành true, duy trì sau 48 giờ tự động biến thành false

  Nhân_vật:
    type: |-
      {
        [Tên_nhân_vật: string]: {
          Miêu_tả_cảnh_tượng: string;
          Suy_nghĩ_nội_tâm: string;
          Họ_tên: string;
          Tuổi: string;
          Giới_tính: string;
          Thân_phận: string;
          Tính_cách: string;
          Kích_thước_ngực: string;
          Trang_phục: {
            Thân_trên: string;
            Thân_dưới: string;
            Đồ_lót: string;
            Giày_tất: string;
            Phụ_kiện: string;
          };
          Đặc_tả: {
            Bộ_phận: string;
            Miêu_tả: string;
          };
          Chỉ_số_mang_thai: number;
          Có_phải_xử_nữ_không: boolean;
          Chỉ_số_hủ_hóa: number;
          Chỉ_số_lý_trí: number;
          Độ_hưng_phấn: number;
          Lượng_tinh_dịch: number;
          Độ_lệ_thuộc: number;
          Tiến_độ_thu_thập_ID: number;
          Trạng_thái_kỳ_sinh_lý: 'Kỳ an toàn' | 'Kỳ rụng trứng' | 'Kỳ kinh nguyệt';
        }
      }
    check:
      - Chỉ giữ lại nhân vật cùng có mặt trong cảnh hiện tại và có khả năng tương tác với {{user}}. Khi chuyển cảnh, xóa bỏ toàn bộ dữ liệu của nhân vật rời khỏi hiện trường
      - Miêu tả_cảnh_tượng bắt buộc cập nhật mỗi lần, miêu tả khách quan 30-60 chữ về hình ảnh hiện tại
      - Suy_nghĩ_nội_tâm phải tuân thủ nghiêm ngặt giai đoạn Chỉ_số_hủ_hóa: 0-49 đầy nhục nhã phẫn nộ/50-99 mâu thuẫn giãy giụa/100+ sùng bái khát khao hoặc biến mất
      - Trang_phục cập nhật theo cốt truyện, khi khỏa thân ghi chú "khỏa thân" hoặc "không"
      - Đặc_tả bắt trọn bộ phận hoặc biểu cảm có sức căng nhất
      - Chỉ_số_hủ_hóa (0~200): Kích thích tình dục +2~+60 tùy cường độ, không kích thích mỗi ngày -1~-3. Giai đoạn: 0-49 kháng cự ban đầu/50-99 dao động hùa theo/100-199 chìm đắm/200 đọa lạc hoàn toàn không tăng thêm nữa
      - Chỉ_số_lý_trí (0~100): Kích thích tình dục -2~-30 tùy cường độ, sau khi thoát ly +2~+5 mỗi 10 phút, ngủ hồi phục 70~90. Chỉ_số_hủ_hóa càng cao giảm càng nhanh hồi phục càng chậm. Về 0 cần ngủ đủ giấc để hồi phục lên trên 20
      - Độ_hưng_phấn (0~100): Lời nói +3~+8, mơn trớn +5~+10, kích thích trọng điểm +10~+20, thâm nhập +15~+30/phút. Đạt 100 kích hoạt cao trào giảm xuống 20~40, thời kỳ không phản ứng 3-8 phút tốc độ tăng giảm một nửa. Sau khi thoát ly -3~-5/phút, ngủ sẽ về 0
      - Lượng_tinh_dịch (ml): Xuất tinh trong tăng thêm = Lượng xuất tinh của nhân vật chính, bài tiết -50~-100, tẩy rửa -30~-80, hấp thụ tự nhiên -10~-20/giờ. Ngưỡng miêu tả: 0-50 không miêu tả/51-200 ẩm ướt/201-500 hơi nhô lên/501-1000 nhô lên rõ rệt/1000+ căng phồng tràn ra ngoài
      - Chỉ_số_mang_thai (0~100): Chỉ tăng khi xuất tinh trong âm đạo. Kỳ rụng trứng một lần = 100 thụ thai ngay/Giai đoạn đầu kỳ an toàn +15~+30/Giai đoạn sau kỳ an toàn +10~+25/Kỳ kinh nguyệt +0. Chưa đạt 100 mỗi ngày -5~-10, đạt 100 xác nhận thụ thai không thay đổi nữa
      - Có_phải_xử_nữ_không: Sau lần đầu chèn vào âm đạo sẽ trở thành false
      - Độ_lệ_thuộc (0~100): Dịu dàng +3~+8, cộng hưởng tình cảm +8~+15, thỏa mãn tình dục +10~+20. Chứng kiến thân mật với người khác -5~-15, bị ghẻ lạnh -3~-8, bị đối xử thô bạo -8~-20
      - Tiến_độ_thu_thập_ID (0~100): Thu thập thông tin cá nhân +15~+30, thiết lập liên kết +10~+20, dụ dỗ tâm lý +20~+40. Đạt 100 có thể đơn phương đăng ký làm vợ
      - Trạng_thái_kỳ_sinh_lý: Tự động tính toán dựa trên ngày bắt đầu chu kỳ và ngày hiện tại. Chu kỳ 28 ngày: Ngày 1-5 kỳ kinh nguyệt/Ngày 6-10 kỳ an toàn/Ngày 11-17 kỳ rụng trứng/Ngày 18-28 kỳ an toàn

  Động_thái_mạng.Bài_đăng_hot:
    type: |-
      {
        Tiêu_đề: string;
        Nội_dung_bài_đăng: string;
        Bình_luận: { [ID_người_dùng: string]: string };
      }
    check:
      - Mỗi lần đều tạo mới toàn bộ, nghiêm cấm lặp lại. Người đăng bài chỉ dựa trên chứng kiến/tin đồn/chụp lén/thông tin công khai, không thể biết nội tâm hoặc cảnh riêng tư của {{user}}
      - Luân phiên các loại: Tường thuật trực tiếp theo dõi/Ảo tưởng ý dâm/Khoe khoang/Treo thưởng/Chia sẻ chụp lén/Trao đổi tình báo/Nhật ký liếm cẩu
      - Đặc tính si nữ: Chiếm hữu bệnh hoạn, ảo tưởng tình dục lộ liễu, mê đắm dịch cơ thể, tranh phong ghen tuông, thảo luận sách lược
      - Tiêu đề ≤ 15 chữ, nội dung 50-150 chữ bao gồm chi tiết cụ thể (Thời gian/Địa điểm/Trang phục/Hành vi), bình luận 3-5 dòng mỗi dòng 20-60 chữ
      - Ngôn ngữ trực diện lộ liễu, nguồn thông tin cần được ám chỉ
